'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { SearchForm } from '@/components/ui/search-form'
import { Input } from '@/components/ui/input'
import { Label } from '@/components/ui/label'

interface ForbiddenSearchFormProps {
    defaultKeyword?: string
}

export function ForbiddenSearchForm({ defaultKeyword }: ForbiddenSearchFormProps) {
    const router = useRouter()
    const [keyword, setKeyword] = useState(defaultKeyword ?? '')

    const handleSearch = () => {
        const params = new URLSearchParams()
        if (keyword) params.set('keyword', keyword)
        params.set('page', '0')
        router.push(`/forbidden?${params.toString()}`)
    }

    const handleReset = () => {
        setKeyword('')
        router.push('/forbidden')
    }

    return (
        <SearchForm onSearch={handleSearch} onReset={handleReset}>
            <div className="flex flex-col gap-1 min-w-[260px]">
                <Label htmlFor="keyword">검색어</Label>
                <Input
                    id="keyword"
                    value={keyword}
                    onChange={(e) => setKeyword(e.target.value)}
                    placeholder="금지어 검색"
                />
            </div>
        </SearchForm>
    )
}

'use client'

import { useState } from 'react'
import { useRouter } from 'next/navigation'
import { format } from 'date-fns'
import { toast } from 'sonner'
import {
    Dialog,
    DialogContent,
    DialogHeader,
    DialogTitle,
} from '@/components/ui/dialog'
import { Button } from '@/components/ui/button'
import { deleteForbiddenWord } from '@/features/forbidden/actions'
import type { ForbiddenItem } from '@/features/forbidden/types'
import { ForbiddenForm } from './ForbiddenForm'

interface ForbiddenDetailPanelProps {
    forbidden: ForbiddenItem | null
    open: boolean
    onOpenChange: (open: boolean) => void
}

export function ForbiddenDetailPanel({ forbidden, open, onOpenChange }: ForbiddenDetailPanelProps) {
    const router = useRouter()
    const [editOpen, setEditOpen] = useState(false)
    const [deleting, setDeleting] = useState(false)

    const handleDelete = async () => {
        if (!forbidden) return
        if (!confirm(`"${forbidden.wordKor}" 금지어를 삭제하시겠습니까?`)) return

        setDeleting(true)
        try {
            const result = await deleteForbiddenWord(forbidden.id)
            if (!result.success) {
                toast.error(result.error ?? '삭제 중 오류가 발생했습니다')
                return
            }
            toast.success('금지어가 삭제되었습니다')
            onOpenChange(false)
            router.refresh()
        } catch {
            toast.error('삭제 중 오류가 발생했습니다')
        } finally {
            setDeleting(false)
        }
    }

    if (!forbidden) return null

    return (
        <>
            <Dialog open={open} onOpenChange={onOpenChange}>
                <DialogContent className="sm:max-w-[480px]">
                    <DialogHeader>
                        <DialogTitle>금지어 상세</DialogTitle>
                    </DialogHeader>
                    <dl className="grid grid-cols-[120px_1fr] gap-x-4 gap-y-3 text-sm">
                        <dt className="font-medium text-slate-500">ID</dt>
                        <dd>{forbidden.id}</dd>
                        <dt className="font-medium text-slate-500">금지어</dt>
                        <dd>{forbidden.wordKor}</dd>
                        <dt className="font-medium text-slate-500">사유</dt>
                        <dd>{forbidden.reason ?? '-'}</dd>
                        <dt className="font-medium text-slate-500">등록일</dt>
                        <dd>{format(new Date(forbidden.createdAt), 'yyyy-MM-dd')}</dd>
                        <dt className="font-medium text-slate-500">수정일</dt>
                        <dd>{format(new Date(forbidden.updatedAt), 'yyyy-MM-dd')}</dd>
                    </dl>
                    <div className="flex justify-end gap-2 pt-4">
                        <Button
                            variant="destructive"
                            onClick={handleDelete}
                            disabled={deleting}
                        >
                            {deleting ? '삭제 중...' : '삭제'}
                        </Button>
                        <Button variant="outline" onClick={() => setEditOpen(true)}>
                            수정
                        </Button>
                    </div>
                </DialogContent>
            </Dialog>

            <ForbiddenForm
                open={editOpen}
                onOpenChange={setEditOpen}
                forbidden={forbidden}
                onSuccess={() => onOpenChange(false)}
            />
        </>
    )
}

'use client'

import { useState } from 'react'
import { format } from 'date-fns'
import type { ColDef, ValueFormatterParams } from 'ag-grid-community'
import { DataTable } from '@/components/ui/data-table'
import { Button } from '@/components/ui/button'
import type { ForbiddenItem } from '@/features/forbidden/types'
import { ForbiddenForm } from './ForbiddenForm'
import { ForbiddenDetailPanel } from './ForbiddenDetailPanel'

interface ForbiddenTableProps {
    items: ForbiddenItem[]
}

const columnDefs: ColDef<ForbiddenItem>[] = [
    { field: 'wordKor', headerName: '금지어', width: 200 },
    { field: 'reason', headerName: '사유', flex: 1 },
    {
        field: 'createdAt',
        headerName: '등록일',
        width: 150,
        valueFormatter: (params: ValueFormatterParams<ForbiddenItem, Date>) =>
            params.value ? format(new Date(params.value), 'yyyy-MM-dd') : '',
    },
]

export function ForbiddenTable({ items }: ForbiddenTableProps) {
    const [createOpen, setCreateOpen] = useState(false)
    const [selectedForbidden, setSelectedForbidden] = useState<ForbiddenItem | null>(null)
    const [detailOpen, setDetailOpen] = useState(false)

    const handleRowClick = (row: ForbiddenItem) => {
        setSelectedForbidden(row)
        setDetailOpen(true)
    }

    return (
        <div>
            <div className="flex justify-end mb-2">
                <Button onClick={() => setCreateOpen(true)}>새 금지어</Button>
            </div>

            <DataTable<ForbiddenItem>
                columnDefs={columnDefs}
                rowData={items}
                onRowClick={handleRowClick}
            />

            <ForbiddenForm
                open={createOpen}
                onOpenChange={setCreateOpen}
                onSuccess={() => {}}
            />

            <ForbiddenDetailPanel
                forbidden={selectedForbidden}
                open={detailOpen}
                onOpenChange={setDetailOpen}
            />
        </div>
    )
}

