'use server'
import { revalidatePath } from 'next/cache'
import { prisma } from '@/lib/prisma'
import { requireAdmin } from '@/lib/auth'
import { forbiddenSaveSchema } from './schema'
import type { ActionResult } from '@/lib/errors'

export async function createForbiddenWord(input: unknown): Promise<ActionResult<{ id: number }>> {
  await requireAdmin()
  const parsed = forbiddenSaveSchema.safeParse(input)
  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }

  let word: { id: number }
  try {
    word = await prisma.forbiddenWord.create({ data: parsed.data })
  } catch {
    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
  }
  revalidatePath('/forbidden')
  return { success: true, data: { id: word.id } }
}

export async function updateForbiddenWord(id: number, input: unknown): Promise<ActionResult> {
  await requireAdmin()
  const parsed = forbiddenSaveSchema.safeParse(input)
  if (!parsed.success) return { success: false, error: '입력값이 올바르지 않습니다', code: 'VALIDATION_ERROR' }

  try {
    await prisma.forbiddenWord.update({ where: { id }, data: parsed.data })
  } catch {
    return { success: false, error: '저장 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
  }
  revalidatePath('/forbidden')
  return { success: true, data: undefined }
}

export async function deleteForbiddenWord(id: number): Promise<ActionResult> {
  await requireAdmin()
  try {
    await prisma.forbiddenWord.delete({ where: { id } })
  } catch {
    return { success: false, error: '삭제 중 오류가 발생했습니다', code: 'INTERNAL_ERROR' as const }
  }
  revalidatePath('/forbidden')
  return { success: true, data: undefined }
}
